(Sorry no static server because it served by Apache, I use reverse proxy with ws mod)

```
var io = require("socket.io").listen(82);
var pty = require("pty.js");

io.sockets.on("connection", function(socket) {
 var buff = [];

 var term = pty.spawn("/usr/bin/ssh", ["root@localhost"], {
  name: "xterm-256color",
  cwd: process.env.HOME,
  env: process.env
 });

 term.on("data", function(data) {
  return !socket ? buff.push(data) : socket.emit("data", data);
 });

 while(buff.length) {
  socket.emit("data", buff.shift());
 }

 socket.on("data", function(data) {
  term.write(data);
 });

 socket.on("resize", function(resize) {
  term.resize(resize.cols, resize.rows);
 });

 socket.on("disconnect", function() {
  socket = null;
  term.kill();
 });
});
```

Hi,
  I try to use pyang to deviate an mandatory configurable leaf to non-mandatory read-only leaf, it turns out that the mandatory property is removed on purpose but 'config false' is not added to that leaf.
  here is the details:
`test.yang`
```
module test {
  yang-version 1.1;

  namespace urn:test;

  prefix test;
  
  container root {
    list child {
      key name;
      leaf name {
        type string;
      }
      leaf foo {
        mandatory true;
        type string;
      }
    }
  }
}
```

the deviation yang model is as following:
`test-dev.yang`
```
module test-dev {
  yang-version 1.1;
  namespace urn:test-dev;
  prefix test-dev;
  import test {
    prefix t;
  }
  deviation /t:root/t:child/t:foo {
    deviate delete {
        mandatory true;
    }
    deviate add {
        config false;
    }
  }
}
```

the result of deviating the `test-dev.yang` to `test.yang` is 
```
$ pyang test.yang --deviation-module=test-dev.yang -f tree
module: test
    +--rw root
       +--rw child* [name]
          +--rw name    string
          +--rw foo?    string
```
the expected result is the `foo` is with `ro` instead of `rw`

version information is
```
$ python --version
Python 3.5.1
$ pyang --version
pyang 1.7
